INSERT INTO `recruit_application` VALUES (27,'康阿辉','22406032001','计算机科学与技术','24级','18297382246','3508008752@QQ.COM','我已是该小组的老油条，一直没加入这个网页，现在申请加入网页',2,'2026-03-10 21:31:55'),(30,'卢明生','22406091018','软件工程','大二','17855266515','2601786558@qq.com','无',2,'2026-03-26 21:08:43'),(31,'倪展博','22306091033','软件工程','23','19556654727','3466247374@qq.com',' ',2,'2026-03-26 21:09:10'),(32,'赵贵宇','22406091013','软件工程','24级','19855643912','3314878566@qq.com','我申请加入小组，一是想把课堂知识落地到实际项目中，提升自己的开发实战能力；二是希望和大家组队交流，学习不同的开发思路，一起完成项目、积累经验，也愿意主动承担编码、文档整理等基础工作，为小组出力。',2,'2026-03-26 21:09:15'),(33,'舒智','22506032001','计算机科学与技术','大一','19215660386','1809385960@qq.com','1',2,'2026-03-26 21:10:55'),(34,'刘鸣燕','22506031033','计算机科学与技术','25级','18055196731','2043225059@qq.com','兴趣',2,'2026-03-26 21:11:27'),(35,'汪莹莹','22406091017','24软件工程','大二','17855375112','111111@qq.com','111',2,'2026-03-26 21:17:11'),(36,'王晓雯','22506032017','计算机科学与技术','2025','13215585194','3300907466@qq.com','软件小组25计科王晓雯',2,'2026-03-26 21:20:00'),(37,'曹子涵','22506091003','软件工程','2025','15755056890','czh520412@qq.com','小组成员',2,'2026-03-26 22:40:04'),(38,'侯智尧','22506091016','软件工程','2025','15855399189','hzy14514475@qq.com','小组成员',2,'2026-03-26 23:09:07'),(39,'褚洋洋','22506091008','软件工程','大一','19856797237','c1838668610@qq.com','学习',2,'2026-03-26 23:22:37'),(40,'赵子辰','22506092034','软件工程','大一','15656789286','1468388135@qq.com','本人自选入软件工程以来，对编程和技术探索感有兴趣。本人性格沉稳细致，善于团队沟通，乐于接受新知识。高中阶段曾自学过一段时间的Python,但自我感觉缺少明亮的火光指引着我该向何处发展。因此，本人希望能成为软件小组的正式成员，在更专业的平台上提升自己的编程能力，以及在学长学姐的谆谆教导中找到前行的方向，与团队成员共同完成挑战性的任务，贡献出自己的一份力量。',2,'2026-03-27 00:29:07'),(41,'付朝阳','22406091020','软件工程','24','18726564157','fzy2006220@qq.com','11',2,'2026-03-27 13:01:14'),(42,'孙玉汇','22406091030','软件工程','2024级','17201535424','1832981599@qq.com','我来自24级软件工程一班，怀着对软件专业的热爱，加入软件小组。',2,'2026-03-27 18:17:45'),(43,'田浩宇','22506091035','软件工程','25级','15551877635','1640949812@qq.com','注册',2,'2026-03-27 18:30:00'),(44,'丁欣蕊','22506091009','软件工程','大一','19315050926','2303618283@qq.com','我是软工一班的丁欣蕊',2,'2026-03-28 21:23:29'),(45,'刘雨纯','22506031035','计科','大一','19930125314','liuyuchun070711@qq.com','.',2,'2026-03-29 18:52:07'),(46,'孟雅丽','22506091028','软件工程','大一','18255157451','yali_217@qq.com','学习更多专业知识',2,'2026-03-29 18:56:05'),(47,'张浩洋','22506092025','软件工程','大一','19719663893','1075720596@qq.com','学长，软件小组，自己人',2,'2026-03-29 19:19:05'),(48,'李彤','22406032018','计算机科学与技术','24','18325930191','2939246620@qq.com','.',2,'2026-03-30 12:35:14'),(49,'童凌峰','22406032042','计算机科学与技术','大二','18098636871','3519501337@qq.com','好好学习，天天向上',2,'2026-03-30 18:54:12'),(50,'张浩洋','22506092025','软件工程','大一','19719663893','1075720596@qq.com','软件小组',2,'2026-04-08 18:48:13'),(53,'张雪晴','22406091004','软件工程','24级','18756791350','3045038938@qq.com','小组成员',2,'2026-04-19 16:39:13'),(54,'王睿喆','22404151038','酒店管理','2024','19955525281','1822686520@qq.com','1',2,'2026-04-20 20:04:21'),(55,'test','123456','测试','大二','11111111111','test123456@qq.com','test',2,'2026-04-22 22:09:03'),(56,'唐超峰','22406091027','软件工程','24软工一班','18196580341','3163439330@qq.com','无',2,'2026-05-04 14:45:37'),(57,'施宇康','22506091032','软件工程','大一','15056236087','2757996719@qq.com','提升\r\n',2,'2026-05-18 19:40:05');
